generated_oml:
// Sensing Components
instance CartHoistMotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder on the cart/hoist motor providing position and velocity"
    DTDFVocab:producedData AggregatedCraneSensorDataTransmission
]

instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder measuring the oscillation of the hoist cable"
    DTDFVocab:producedData AggregatedCraneSensorDataTransmission
]

instance AnemometerSensor : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed during crane operation"
    DTDFVocab:producedData AggregatedCraneSensorDataTransmission
]

// Physical-to-virtual data transmission
instance AggregatedCraneSensorDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CartHoistMotorEncoder, SwingAngleEncoder, AnemometerSensor
]

// Digital Twin Data
instance CraneStateTimeSeriesData : DTDFVocab:Data [
    base:desc "Time‑stamped state data of the crane (motor positions, encoder counts, swing angle, wind speed) stored in TimescaleDB"
    DTDFVocab:fromData AggregatedCraneSensorDataTransmission
]

instance TrajectoryDataFile : DTDFVocab:Model [
    base:desc "Trajectory data files generated by the Trajectory Generator"
    DTDFVocab:inputTo SimulatorEnabler
]

instance SimulationOutputDataFile : DTDFVocab:Data [
    base:desc "Simulation outputs used for validation and fault classification"
    DTDFVocab:fromData TrajectoryDataFile
]

// Models
instance CADModelGantryCrane : DTDFVocab:Model [
    base:desc "CAD models of the crane geometry"
    DTDFVocab:inputTo TrajectoryGeneratorEnabler
]

instance KinematicModelFirstPrinciples : DTDFVocab:Model [
    base:desc "First‑principles kinematic model used for trajectory planning and simulation"
    DTDFVocab:inputTo TrajectoryGeneratorEnabler
]

instance FaultDetectionModel : DTDFVocab:Model [
    base:desc "Time‑series classification model for fault detection"
    DTDFVocab:inputTo FaultDetectionEnabler
]

// Enablers
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB container for time‑series storage"
    DTDFVocab:enables DataLoggerService, ValidationService
]

instance MosquittoBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker container"
    DTDFVocab:enables TrajectoryGeneratorService
]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana dashboard container for data visualization"
    DTDFVocab:enables VisualizationService
]

instance TrajectoryGeneratorEnabler : DTDFVocab:Enabler [
    base:desc "Trajectory Generator Service container"
    DTDFVocab:enables TrajectoryGeneratorService
]

instance SimulatorEnabler : DTDFVocab:Enabler [
    base:desc "Simulator Service container"
    DTDFVocab:enables SimulationService
]

instance ValidationEnabler : DTDFVocab:Enabler [
    base:desc "Continuous Validation Service container"
    DTDFVocab:enables ValidationService
]

instance FaultDetectionEnabler : DTDFVocab:Enabler [
    base:desc "Fault Detection Service container"
    DTDFVocab:enables FaultDetectionService
]

instance HMIEnabler : DTDFVocab:Enabler [
    base:desc "Human‑Machine Interface Service container"
    DTDFVocab:enables HMIService
]

// Services
instance TrajectoryGeneratorService : DTDFVocab:Service [
    base:desc "Generates optimal, swing‑free trajectory plans using the kinematic model"
    DTDFVocab:provides RealTimeTrajectoryPlanInsight, SwingFreeTrajectoryInsight
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Simulates the crane and its controllers for validation"
]

instance ValidationService : DTDFVocab:Service [
    base:desc "Continuously validates executed trajectories against simulation data and computes distance metrics"
    DTDFVocab:provides ValidationAlertInsight, DeviationFlagInsight
]

instance FaultDetectionService : DTDFVocab:Service [
    base:desc "Performs fault detection via time‑series classification"
    DTDFVocab:provides FaultDetectionInsight
]

instance DataLoggerService : DTDFVocab:Service [
    base:desc "Logs state, control, and sensor signals into TimescaleDB"
    DTDFVocab:provides DataLoggingInsight
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Provides Grafana dashboards for performance metrics and validation alerts"
    DTDFVocab:provides PerformanceMetricInsight, ValidationAlertInsight
]

instance HMIService : DTDFVocab:Service [
    base:desc "Allows operators to adjust control parameters and intervene manually"
    DTDFVocab:provides AdjustControlParametersAction, ManualInterventionAction
]

// Insights
instance RealTimeTrajectoryPlanInsight : DTDFVocab:Insight [
    base:desc "Real‑time trajectory plans presented to operators"
]

instance SwingFreeTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Optimal swing‑free trajectory plan"
]

instance ValidationAlertInsight : DTDFVocab:Insight [
    base:desc "Alert when deviations exceed tolerance during validation"
]

instance DeviationFlagInsight : DTDFVocab:Insight [
    base:desc "Flag indicating deviations from planned trajectory"
]

instance PerformanceMetricInsight : DTDFVocab:Insight [
    base:desc "Performance metrics displayed in Grafana dashboards"
]

instance FaultDetectionInsight : DTDFVocab:Insight [
    base:desc "Results of fault classification from time‑series analysis"
]

instance DataLoggingInsight : DTDFVocab:Insight [
    base:desc "Confirmation of successful data logging into TimescaleDB"
]

// Actions
instance AdjustControlParametersAction : DTDFVocab:Action [
    base:desc "Operator‑initiated adjustment of control parameters"
    DTDFVocab:IsAutomatic false
]

instance ManualInterventionAction : DTDFVocab:Action [
    base:desc "Manual operator intervention in the crane control loop"
    DTDFVocab:IsAutomatic false
]

// Acting Components
instance PhysicalCraneInterface : DTDFVocab:ActingComponent [
    base:desc "Interface that issues commands to cart and hoist stepper motors via TMC4671 drivers over serial/USB"
]

// Environment
instance LabScaleGantryCraneEnvironment : DTDFVocab:Environment [
    base:contains CartComponent, HoistComponent, ElectromagnetComponent, RailComponent
]

instance CartComponent : DTDFVocab:Component [
    base:desc "Cart moving along the rail"
]

instance HoistComponent : DTDFVocab:Component [
    base:desc "Hoist cable facilitating vertical lift"
]

instance ElectromagnetComponent : DTDFVocab:Component [
    base:desc "Electromagnet for grabbing containers"
]

instance RailComponent : DTDFVocab:Component [
    base:desc "Rectangular rail along which the cart moves"
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The Digital Twin’s Control Application generates motor commands (step pulses or PWM commands) to achieve a desired trajectory. It serially transmits these commands through the Physical Crane Interface to the TMC4671 motor drivers, which drive the cart and hoist motors. No intermediate MQTT layer is used for PT–DT control traffic."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "All services operate continuously in real time. The Logging Application logs sensor data at the native sampling rate of the sensors (≈10 Hz to 100 Hz as implied by the rotor and motor drivers), the Continuous Validation Service performs continuous checks each cycle, and the Dashboard updates in real time. There is no explicit discrete campaign mode mentioned."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A C4‑model based architecture with several containers: on the physical side the crane, its interface, control, logging, and HMI; on the digital side the MQTT broker, database, dashboard, trajectory generator, simulator, and continuous validation services. The entire constellation is deployed via a single docker‑compose configuration on a personal PC, providing a coherent twin ecosystem."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design – CAD models (Autodesk Fusion 360) and kinematic models; Manufacturing – physical assembly of the crane hardware (motors, controllers, Arduino board, shield); Operation – runtime twin services (logging, simulation, validation) that interact with the PT during daily use."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous validation ensures model fidelity by comparing live sensor data against simulated trajectories; distance metrics are computed and threshold breaches trigger alerts. Time‑series classification techniques are applied to detect faults. All models are validated against measured data during operation, and uncertainty is managed by confidence bounds displayed in the Grafana dashboards."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "The Physical Crane Interface communicates with the Arduino via a UART serial link over USB. The interface writes data to TimescaleDB over the PostgreSQL wire protocol. Services exchange messages via the Eclipse Mosquitto MQTT broker over standard MQTT protocol on localhost. The Docker Compose network exposes HTTP endpoints for Grafana and database clients. All communications use TCP sockets."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "All digital twin components are containerized with Docker, launched using docker‑compose on a commodity PC. The host OS is unspecified but typically Linux; the Docker network provides isolation and easy scaling of individual services."
]
